/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Duplicatas"
//Report Template Source Header if &Context.EmpCod = 0 loadWWPContext.Call(&Context) Endif
For Each ORder EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &AppName = FilFan
&AddressLine1 = &Today.ToFormattedString() + ' ' + &Time.Trim() //FilLogNro.Trim() + ' - ' + FilBai.Trim() + ', '+ FilCidCodNomUfe.Trim()
&AddressLine2 = FilFonNum.Trim() if not FilEml.IsEmpty() if not &AddressLine2.IsEmpty() &AddressLine2 += ' / ' Endif &AddressLine2 += FilEml.Trim() Endif Exit EndFor
Print printTitle End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &CreCliCod.IsEmpty() print printBlockFilterCreCliCod EndIf If not &CreCliRaz.IsEmpty() print printBlockFilterCreCliRaz EndIf If not &CreIsPer.IsEmpty() print printBlockFilterCreIsPer EndIf If not &CreSts.IsEmpty() &FilterCreStsValueDescription = &CreSts.EnumerationDescription()
print printBlockFilterCreSts EndIf If not &CreRecPag.IsEmpty() &FilterCreRecPagValueDescription = &CreRecPag.EnumerationDescription()
print printBlockFilterCreRecPag EndIf If not &CreVlrSdo.IsEmpty() print printBlockFilterCreVlrSdo EndIf If not &auxCreFrpPgtoTip.IsEmpty() &FilterauxCreFrpPgtoTipValueDescription = &auxCreFrpPgtoTip.EnumerationDescription()
print printBlockFilterauxCreFrpPgtoTip EndIf If not &CreFilPgt.IsEmpty() print printBlockFilterCreFilPgt EndIf If not &CreDtaVct.IsEmpty() print printBlockFilterCreDtaVct EndIf If not &CreDtaVct_To.IsEmpty() &CreDtaVct_To_Description = format('%1 (%2)', "Vct.", " - ") print printBlockFilterCreDtaVct_To EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CREDUPNRO' &CreDupNro1.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro1.IsEmpty() &CreDupNro = &CreDupNro1 print printBlockFilterCreDupNro EndIf Case &DynamicFiltersSelector1 = !'CRECBRCOD' &CreCbrCod1.FromString(&GridStateDynamicFilter.Value) If not &CreCbrCod1.IsEmpty() &CreCbrCod = &CreCbrCod1 print printBlockFilterCreCbrCod EndIf Case &DynamicFiltersSelector1 = !'CRECBRNOM' &CreCbrNom1.FromString(&GridStateDynamicFilter.Value) If not &CreCbrNom1.IsEmpty() &CreCbrNom = &CreCbrNom1 print printBlockFilterCreCbrNom EndIf Case &DynamicFiltersSelector1 = !'CREVENCOD' &CreVenCod1.FromString(&GridStateDynamicFilter.Value) If not &CreVenCod1.IsEmpty() &CreVenCod = &CreVenCod1 print printBlockFilterCreVenCod EndIf Case &DynamicFiltersSelector1 = !'CREBLONRO' &CreBloNro1.FromString(&GridStateDynamicFilter.Value) If not &CreBloNro1.IsEmpty() &CreBloNro = &CreBloNro1 print printBlockFilterCreBloNro EndIf Case &DynamicFiltersSelector1 = !'CREVLRDUP' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CreVlrDup1.FromString(&GridStateDynamicFilter.Value) If not &CreVlrDup1.IsEmpty() Do Case Case &DynamicFiltersOperator1 = 0 &FilterCreVlrDupDescription = format('%1 (%2)', "Valor Dup.", "<") Case &DynamicFiltersOperator1 = 1 &FilterCreVlrDupDescription = format('%1 (%2)', "Valor Dup.", "=") Case &DynamicFiltersOperator1 = 2 &FilterCreVlrDupDescription = format('%1 (%2)', "Valor Dup.", ">") EndCase &CreVlrDup = &CreVlrDup1 print printBlockFilterCreVlrDup EndIf Case &DynamicFiltersSelector1 = !'CREFRPPGTOTIP' &CreFrpPgtoTip1.FromString(&GridStateDynamicFilter.Value) If not &CreFrpPgtoTip1.IsEmpty() &FilterCreFrpPgtoTip1ValueDescription = &CreFrpPgtoTip1.EnumerationDescription()
&FilterCreFrpPgtoTipValueDescription = &FilterCreFrpPgtoTip1ValueDescription print printBlockFilterCreFrpPgtoTip EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CREDUPNRO' &CreDupNro2.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro2.IsEmpty() &CreDupNro = &CreDupNro2 print printBlockFilterCreDupNro EndIf Case &DynamicFiltersSelector2 = !'CRECBRCOD' &CreCbrCod2.FromString(&GridStateDynamicFilter.Value) If not &CreCbrCod2.IsEmpty() &CreCbrCod = &CreCbrCod2 print printBlockFilterCreCbrCod EndIf Case &DynamicFiltersSelector2 = !'CRECBRNOM' &CreCbrNom2.FromString(&GridStateDynamicFilter.Value) If not &CreCbrNom2.IsEmpty() &CreCbrNom = &CreCbrNom2 print printBlockFilterCreCbrNom EndIf Case &DynamicFiltersSelector2 = !'CREVENCOD' &CreVenCod2.FromString(&GridStateDynamicFilter.Value) If not &CreVenCod2.IsEmpty() &CreVenCod = &CreVenCod2 print printBlockFilterCreVenCod EndIf Case &DynamicFiltersSelector2 = !'CREBLONRO' &CreBloNro2.FromString(&GridStateDynamicFilter.Value) If not &CreBloNro2.IsEmpty() &CreBloNro = &CreBloNro2 print printBlockFilterCreBloNro EndIf Case &DynamicFiltersSelector2 = !'CREVLRDUP' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CreVlrDup2.FromString(&GridStateDynamicFilter.Value) If not &CreVlrDup2.IsEmpty() Do Case Case &DynamicFiltersOperator2 = 0 &FilterCreVlrDupDescription = format('%1 (%2)', "Valor Dup.", "<") Case &DynamicFiltersOperator2 = 1 &FilterCreVlrDupDescription = format('%1 (%2)', "Valor Dup.", "=") Case &DynamicFiltersOperator2 = 2 &FilterCreVlrDupDescription = format('%1 (%2)', "Valor Dup.", ">") EndCase &CreVlrDup = &CreVlrDup2 print printBlockFilterCreVlrDup EndIf Case &DynamicFiltersSelector2 = !'CREFRPPGTOTIP' &CreFrpPgtoTip2.FromString(&GridStateDynamicFilter.Value) If not &CreFrpPgtoTip2.IsEmpty() &FilterCreFrpPgtoTip2ValueDescription = &CreFrpPgtoTip2.EnumerationDescription()
&FilterCreFrpPgtoTipValueDescription = &FilterCreFrpPgtoTip2ValueDescription print printBlockFilterCreFrpPgtoTip EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CREDUPNRO' &CreDupNro3.FromString(&GridStateDynamicFilter.Value) If not &CreDupNro3.IsEmpty() &CreDupNro = &CreDupNro3 print printBlockFilterCreDupNro EndIf Case &DynamicFiltersSelector3 = !'CRECBRCOD' &CreCbrCod3.FromString(&GridStateDynamicFilter.Value) If not &CreCbrCod3.IsEmpty() &CreCbrCod = &CreCbrCod3 print printBlockFilterCreCbrCod EndIf Case &DynamicFiltersSelector3 = !'CRECBRNOM' &CreCbrNom3.FromString(&GridStateDynamicFilter.Value) If not &CreCbrNom3.IsEmpty() &CreCbrNom = &CreCbrNom3 print printBlockFilterCreCbrNom EndIf Case &DynamicFiltersSelector3 = !'CREVENCOD' &CreVenCod3.FromString(&GridStateDynamicFilter.Value) If not &CreVenCod3.IsEmpty() &CreVenCod = &CreVenCod3 print printBlockFilterCreVenCod EndIf Case &DynamicFiltersSelector3 = !'CREBLONRO' &CreBloNro3.FromString(&GridStateDynamicFilter.Value) If not &CreBloNro3.IsEmpty() &CreBloNro = &CreBloNro3 print printBlockFilterCreBloNro EndIf Case &DynamicFiltersSelector3 = !'CREVLRDUP' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CreVlrDup3.FromString(&GridStateDynamicFilter.Value) If not &CreVlrDup3.IsEmpty() Do Case Case &DynamicFiltersOperator3 = 0 &FilterCreVlrDupDescription = format('%1 (%2)', "Valor Dup.", "<") Case &DynamicFiltersOperator3 = 1 &FilterCreVlrDupDescription = format('%1 (%2)', "Valor Dup.", "=") Case &DynamicFiltersOperator3 = 2 &FilterCreVlrDupDescription = format('%1 (%2)', "Valor Dup.", ">") EndCase &CreVlrDup = &CreVlrDup3 print printBlockFilterCreVlrDup EndIf Case &DynamicFiltersSelector3 = !'CREFRPPGTOTIP' &CreFrpPgtoTip3.FromString(&GridStateDynamicFilter.Value) If not &CreFrpPgtoTip3.IsEmpty() &FilterCreFrpPgtoTip3ValueDescription = &CreFrpPgtoTip3.EnumerationDescription()
&FilterCreFrpPgtoTipValueDescription = &FilterCreFrpPgtoTip3ValueDescription print printBlockFilterCreFrpPgtoTip EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod CreRecPag FilCod CreDtaVct when &OrderedBy = 1 order EmpCod CreRecPag FilCod (CreDtaVct) when &OrderedBy = 2 order EmpCod CreRecPag FilCod CreDupNro when &OrderedBy = 3 order EmpCod CreRecPag FilCod CreCliCod when &OrderedBy = 4 order EmpCod CreRecPag FilCod CreCliRaz when &OrderedBy = 5 order CreDupNro when &OrderedBy = 6 AND &OrderedDsc = False order (CreDupNro) when &OrderedBy = 6 AND &OrderedDsc = True order CreDtaEms when &OrderedBy = 7 AND &OrderedDsc = False order (CreDtaEms) when &OrderedBy = 7 AND &OrderedDsc = True order CreDtaVct when &OrderedBy = 8 AND &OrderedDsc = False order (CreDtaVct) when &OrderedBy = 8 AND &OrderedDsc = True order CreDtaCob when &OrderedBy = 9 AND &OrderedDsc = False order (CreDtaCob) when &OrderedBy = 9 AND &OrderedDsc = True order CreVlrDup when &OrderedBy = 10 AND &OrderedDsc = False order (CreVlrDup) when &OrderedBy = 10 AND &OrderedDsc = True order CreBloNro when &OrderedBy = 11 AND &OrderedDsc = False order (CreBloNro) when &OrderedBy = 11 AND &OrderedDsc = True
using DSwwDuplicataReceber(&CreCliCod, &CreCliRaz, &CreIsPer, &CreSts, &CreRecPag, &CreVlrSdo , &auxCreFrpPgtoTip, &CreFilPgt, &CreDtaVct, &CreDtaVct_To, &DynamicFiltersSelector1, &DynamicFiltersOperator1 , &CreDupNro1, &CreCbrCod1, &CreCbrNom1, &CreVenCod1, &CreBloNro1, &CreVlrDup1 , &CreFrpPgtoTip1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &DynamicFiltersOperator2, &CreDupNro2, &CreCbrCod2 , &CreCbrNom2, &CreVenCod2, &CreBloNro2, &CreVlrDup2, &CreFrpPgtoTip2, &DynamicFiltersEnabled3 , &DynamicFiltersSelector3, &DynamicFiltersOperator3, &CreDupNro3, &CreCbrCod3, &CreCbrNom3, &CreVenCod3 , &CreBloNro3, &CreVlrDup3, &CreFrpPgtoTip3) if CreNovCliRaz_Formula.Length() > 30 &CreNovCliRaz = substr(CreNovCliRaz_Formula, 1, 30) + '...' Else &CreNovCliRaz = CreNovCliRaz_Formula EndIf if CreAbvDup.IsEmpty() or CreAbvDup.IsNull() AtualizaSaldoDuplicata.Call(EmpCod, CreCod, FilCod) &AuxPedido = CreAbvDup_FORMULA Else &AuxPedido = CreAbvDup Endif
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wwDuplicataReceberGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wwDuplicataReceberGridState")) Else &GridState.FromXml(&Session.Get(!"wwDuplicataReceberGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"CRECLICOD" &CreCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRECLIRAZ" &CreCliRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREISPER" &CreIsPer.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRESTS" &CreSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CRERECPAG" &CreRecPag.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREVLRSDO" &CreVlrSdo.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"AUXCREFRPPGTOTIP" &auxCreFrpPgtoTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREFILPGT" &CreFilPgt.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CREDTAVCT" &CreDtaVct.FromString(&GridStateFilterValue.Value) &CreDtaVct_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforePrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterPrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

Output_file("ExportReportwwDuplicataReceber","PDF");

